import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String command = reader.readLine();

            // Implementing security measures to prevent command injection
            String[] cmdArray = { "/bin/bash", "-c", command }; // on Unix/Linux systems
            // String[] cmdArray = { "cmd.exe", "/c", command }; // on Windows systems

            Process process = Runtime.getRuntime().exec(cmdArray);

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

